import numpy as np

class RMSProp:
    def __init__(self, lr: float = 0.001, beta: float = 0.9, eps: float = 1e-8):
        self.lr = lr
        self.beta = beta
        self.eps = eps
        self.v = None

    def step(self, params: list[np.ndarray], grads: list[np.ndarray]) -> None:
        if self.v is None:
            self.v = [np.zeros_like(p) for p in params]
        for v, p, g in zip(self.v, params, grads):
            v *= self.beta
            v += (1 - self.beta) * g ** 2
            p -= (self.lr / (np.sqrt(v) + self.eps)) * g
